import{_ as t,c as d,o as r,a4 as s}from"./chunks/framework.I1cCAST3.js";const o="/assets/term.CMIGQ3fp.png",b=JSON.parse('{"title":"终端设置","description":"","frontmatter":{},"headers":[],"relativePath":"docs/settings/terminal/index.md","filePath":"docs/settings/terminal/index.md"}'),e={name:"docs/settings/terminal/index.md"},a=s('<h1 id="终端设置" tabindex="-1">终端设置 <a class="header-anchor" href="#终端设置" aria-label="Permalink to &quot;终端设置&quot;">​</a></h1><p>配置终端仿真、字体、光标样式、回滚量和输入行为。</p><p><img src="'+o+'" alt=""></p><h2 id="设置概览" tabindex="-1">设置概览 <a class="header-anchor" href="#设置概览" aria-label="Permalink to &quot;设置概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>设置项</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><strong>终端类型</strong></td><td>xterm</td><td>终端模拟器类型。可选项包括 xterm、vt100 等。</td></tr><tr><td><strong>字体</strong></td><td>Monaco / Menlo</td><td>终端使用的等宽字体。</td></tr><tr><td><strong>字体大小</strong></td><td>14 px</td><td>终端文本的字体大小。</td></tr><tr><td><strong>回滚量</strong></td><td>1000 行</td><td>终端历史记录保留的行数。</td></tr><tr><td><strong>光标样式</strong></td><td>块状</td><td>光标形状：块状（Block）、下划线（Underline）或竖线（Bar）。</td></tr><tr><td><strong>触摸板缩放</strong></td><td>关闭</td><td>开启捏合缩放手势以调整终端字体大小。</td></tr><tr><td><strong>SSH Agents</strong></td><td>--</td><td>SSH 密钥代理和转发配置。</td></tr><tr><td><strong>代理</strong></td><td>--</td><td>终端连接的网络代理。</td></tr><tr><td><strong>鼠标中键</strong></td><td>粘贴</td><td>在终端中点击鼠标中键触发的操作。</td></tr><tr><td><strong>鼠标右键</strong></td><td>上下文菜单</td><td>在终端中点击鼠标右键触发的操作。</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">字体建议</p><p>使用等宽字体（如 Monaco、Menlo、Consolas、JetBrains Mono）以确保代码和命令输出对齐整齐。12--14 px 的字体大小在大多数显示器上效果良好。</p></div><div class="warning custom-block"><p class="custom-block-title">回滚量内存占用</p><p>较高的回滚量会消耗更多内存。对于大多数工作场景，1000--5000 行已经足够。如果您需要经常查看大量日志输出，建议将输出重定向到文件或使用终端搜索（<code>Cmd + F</code> / <code>Ctrl + F</code>）代替。</p></div><h2 id="ssh-agents" tabindex="-1">SSH Agents <a class="header-anchor" href="#ssh-agents" aria-label="Permalink to &quot;SSH Agents&quot;">​</a></h2><p>SSH Agent 设置用于管理密钥和启用代理转发，适用于跳板机等场景。</p><ul><li><strong>SSH Agent 转发</strong> -- 通过远程连接转发本地 SSH Agent，使您无需复制密钥即可在第二台主机上进行认证。</li><li><strong>密钥管理</strong> -- 添加、删除或调整用于连接的 SSH 密钥顺序。</li><li><strong>自动认证</strong> -- 配置后，Chaterm 在连接时会自动使用相应的密钥进行认证。</li></ul><h2 id="代理配置" tabindex="-1">代理配置 <a class="header-anchor" href="#代理配置" aria-label="Permalink to &quot;代理配置&quot;">​</a></h2><p>通过网络代理路由终端连接。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>协议</strong></td><td>HTTP、HTTPS 或 SOCKS5。</td></tr><tr><td><strong>地址</strong></td><td>代理服务器的主机名或 IP 地址。</td></tr><tr><td><strong>端口</strong></td><td>代理服务器的端口号。</td></tr><tr><td><strong>用户名 / 密码</strong></td><td>如果代理需要认证，提供相应凭证。</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>代理设置适用于所有终端连接。配置错误可能导致连接失败。保存前请确认代理地址和端口的正确性。</p></div><h2 id="另请参阅" tabindex="-1">另请参阅 <a class="header-anchor" href="#另请参阅" aria-label="Permalink to &quot;另请参阅&quot;">​</a></h2><ul><li><a href="/docs/settings/general/">通用设置</a> -- 主题、语言、布局和编辑器选项</li><li><a href="/docs/settings/shortcuts/">快捷键设置</a> -- 终端操作等功能的键盘快捷键</li></ul>',16),n=[a];function i(l,c,g,h,p,m){return r(),d("div",null,n)}const u=t(e,[["render",i]]);export{b as __pageData,u as default};
